holoso_fmul_ilog2_const #(
    .WEXP(4), .WMAN(8), .K(7), .STAGE_INPUT(0), .STAGE_DECODE(0), .LATENCY(1)
) u_fmul_ilog2_const_ea2ed72b_0 (
    .clk(clk), .rst(rst), .in_valid(uc_issue_fmul_ilog2_const_ea2ed72b_0),
    .a_sgnop(uc_fmul_ilog2_const_ea2ed72b_0_asgn),
    .y_sgnop(uc_fmul_ilog2_const_ea2ed72b_0_y0sgn),
    .a(s_fmul_ilog2_const_ea2ed72b_0_a),
    .out_valid(),
    .y(s_fmul_ilog2_const_ea2ed72b_0_y0)
