assign err = 1'b0;

// Next-PC sequencer (combinational). The PC holds at the accept (pc==0) and present (pc==LASTPC) boundaries; bubble
// steps carry a NOP word and the PC keeps advancing. The executing step lags the fetch PC by FETCH_LAG. A block's
// terminator redirects the fetch PC at the block's boundary step (a branch reads its boolean register). Each branch
// also sets transacting_in -- 1 for a live accept/body word, 0 at the boundaries -- so each branch tags its own word.
always @* begin
    if (rst) begin
        next_pc        = 0;
        transacting_in = 1'b0;
    end else if (out_valid) begin  // present: hold until the result is taken
        next_pc        = out_ready ? 0 : LASTPC;
        transacting_in = 1'b0;
    end else if (in_ready) begin   // accept: hold until a transaction arrives
        next_pc        = in_valid ? 1 : 0;
        transacting_in = in_valid;
    end else begin                 // advance the fetch: the body of a live transaction
        transacting_in = 1'b1;
        case (pc)
            1: next_pc = bregs[1] ? 6 : 2;
            5: next_pc = 120;
            10: next_pc = bregs[3] ? 19 : 11;
            18: next_pc = 120;
            23: next_pc = bregs[3] ? 116 : 24;
            28: next_pc = bregs[3] ? 105 : 29;
            33: next_pc = bregs[3] ? 97 : 34;
            96: next_pc = 120;
            104: next_pc = 120;
            115: next_pc = 120;
            default: next_pc = pc + 1'b1;
        endcase
    end
end

// Operand read muxes: a per-port case over the read codebook (registers and constants), driving the wrapper.
always @* begin
    case (uc_fcmp_46863199_0_ard)
        3'd0: s_fcmp_46863199_0_a = regs[0];
        3'd1: s_fcmp_46863199_0_a = regs[2];
        3'd2: s_fcmp_46863199_0_a = const_3;
        3'd3: s_fcmp_46863199_0_a = const_5;
        3'd4: s_fcmp_46863199_0_a = const_6;
        default: s_fcmp_46863199_0_a = const_1;
    endcase
    case (uc_fcmp_46863199_0_brd)
        2'd0: s_fcmp_46863199_0_b = regs[1];
        2'd1: s_fcmp_46863199_0_b = regs[5];
        2'd2: s_fcmp_46863199_0_b = const_3;
        default: s_fcmp_46863199_0_b = const_1;
    endcase
    case (uc_fadd_bc41e5c3_0_ard)
        2'd0: s_fadd_bc41e5c3_0_a = regs[2];
        2'd1: s_fadd_bc41e5c3_0_a = regs[7];
        2'd2: s_fadd_bc41e5c3_0_a = const_0;
        default: s_fadd_bc41e5c3_0_a = const_1;
    endcase
    case (uc_fadd_bc41e5c3_0_brd)
        2'd0: s_fadd_bc41e5c3_0_b = regs[0];
        2'd1: s_fadd_bc41e5c3_0_b = regs[1];
        2'd2: s_fadd_bc41e5c3_0_b = regs[5];
        default: s_fadd_bc41e5c3_0_b = const_1;
    endcase
    s_fmul_ilog2_const_085a5e09_0_a = regs[4];
    s_fmul_ilog2_const_6b5098c4_0_a = regs[2];
    s_fmul_ilog2_const_ea2ed72b_0_a = regs[6];
end

// All sequential logic in one clocked process. Reset gates only the control state (pc, err_pc_q, transacting_q) and the
// persistent state registers; every other register is reset-unconditional. Each is driven by exactly one statement.
always @(posedge clk) begin
    // Microcode fetch: PC latch; ucode_word pipelines ucode_q.
    ucode_addr_q <= next_pc;
    ucode_word   <= ucode_q;

    // Register writes (reset-unconditional): one opcode-selected statement per register.
    if (uc_op_r3) regs[3] <= s_fadd_bc41e5c3_0_y0;
    case (uc_op_r4)
        2'd1: regs[4] <= (bregs[1] ? regs[3] : regs[2]);
        2'd2: regs[4] <= (bregs[3] ? regs[3] : regs[5]);
    endcase
    if (uc_op_r5) regs[5] <= s_fmul_ilog2_const_085a5e09_0_y0;
    if (uc_op_r6) regs[6] <= holoso_ffrombool(bregs[0]);
    if (uc_op_r7) regs[7] <= s_fmul_ilog2_const_ea2ed72b_0_y0;
    if (in_ready && in_valid) bregs[0] <= in_rx;
    case (uc_op_b3)
        3'd1: bregs[3] <= ~s_fcmp_46863199_0_y0;
        3'd2: bregs[3] <= ~s_fcmp_46863199_0_y2;
        3'd3: bregs[3] <= s_fcmp_46863199_0_y0;
        3'd4: bregs[3] <= 1'b0;
        3'd5: bregs[3] <= bregs[1] ^ bregs[3];
        3'd6: bregs[3] <= bregs[2] ^ bregs[3];
    endcase
    case (uc_op_b4)
        2'd1: bregs[4] <= 1'b0;
        2'd2: bregs[4] <= 1'b1;
    endcase
    case (uc_op_b5)
        2'd1: bregs[5] <= 1'b0;
        2'd2: bregs[5] <= ~bregs[0];
    endcase

    // Control and persistent state: the reset-gated registers.
    if (rst) begin
        pc            <= 0;
        err_pc_q      <= 0;
        transacting_q <= 0;
        regs[0] <= 12'h000;  // _count reset snapshot
        regs[1] <= 12'h000;  // _index reset snapshot
        regs[2] <= 12'h000;  // _char reset snapshot
        bregs[1] <= 1'b0;  // _busy reset snapshot
        bregs[2] <= 1'b0;  // _parity_rx reset snapshot
    end else begin
        pc <= next_pc;
        transacting_q <= (transacting_q << 1) | transacting_in;
        if (err) err_pc_q <= pc - FETCH_LAG;  // err wins; execution lags the fetch PC by FETCH_LAG, so step is pc-lag
        else if (in_ready && in_valid) err_pc_q <= 0;  // clear the diagnostic when a new transaction is accepted
        case (uc_op_r0)
            3'd1: regs[0] <= s_fadd_bc41e5c3_0_y0;
            3'd2: regs[0] <= s_fmul_ilog2_const_6b5098c4_0_y0;
            3'd3: regs[0] <= const_2;
            3'd4: regs[0] <= (bregs[0] ? regs[0] : const_2);
            3'd5: regs[0] <= (~bregs[0] ? const_4 : regs[0]);
        endcase
        case (uc_op_r1)
            2'd1: regs[1] <= s_fadd_bc41e5c3_0_y0;
            2'd2: regs[1] <= (bregs[0] ? regs[1] : const_0);
            2'd3: regs[1] <= (~bregs[0] ? const_3 : regs[1]);
        endcase
        case (uc_op_r2)
            2'd1: regs[2] <= s_fadd_bc41e5c3_0_y0;
            2'd2: regs[2] <= (~bregs[0] ? const_3 : regs[2]);
        endcase
        case (uc_op_b1)
            3'd1: bregs[1] <= ~s_fcmp_46863199_0_y2;
            3'd2: bregs[1] <= bregs[1] ^ bregs[3];
            3'd3: bregs[1] <= 1'b0;
            3'd4: bregs[1] <= ~bregs[0] & bregs[1];
            3'd5: bregs[1] <= ~bregs[0] | bregs[1];
        endcase
        if (uc_op_b2) bregs[2] <= bregs[0];
    end
end

assign in_ready  = (pc == 0);
assign out_valid = (pc == LASTPC);  // result valid on PRESENT; execution lags the fetch by FETCH_LAG
assign err_pc    = err_pc_q;
assign out_0 = bregs[4];
assign out_1 = regs[2];
assign out_2 = bregs[3];
assign out_3 = bregs[5];

